class MainQueue extends Core{queue(){const queue=EventQueue.getInstance(),preferences=CookiesEntity.getInstance();queue.queue({event:"click",target:$("[data-gdpr-concession]"),handler:event=>(new DashboardSettingsGDPRView).render(event)}),queue.queue({event:"ready",handler:()=>(new DashboardSettingsGDPRView).render(preferences.get("GDPR"))}),queue.queue({event:"click",target:$("[data-theme-switch]"),handler:event=>{(new DashboardSettingsThemesView).render(event),$(event.currentTarget).toggleClass("active").siblings().toggleClass("active")}}),queue.queue({event:"click",target:$("[data-hero-search]"),handler:()=>{$("#hero").toggleClass("d-none")}}),queue.queue({event:"keydown",handler:event=>{(event?.key=="Escape"||event?.keyCode=="Escape")&&$("#hero").addClass("d-none")}}),queue.queue({event:"ready",handler:()=>(new DashboardSettingsThemesView).render(preferences.get("theme"))})}}